// scripts/balance-phase4-iad-merge.mjs
//
// Merge per-shard Balance IAD outputs into a unified `_iad-merged/` dir
// suitable for the IAD-style regret reducer
// (`balance-phase4-iad-regret.mjs --in <merged>`).
//
// Each shard produces (from balance-phase15-bayes-floor.mjs):
//   - manifest.json (per-shard args, with seedStart/seeds=1 differing)
//   - trial-outcomes.csv (per-(cell,seed,mode) rows)
//   - bayes-regret.csv (per-trial paired regret data)
//   - bayes-regret-summary.csv (aggregated; regenerated by the regret reducer)
//   - signature-observations.jsonl, observation-parity.jsonl, etc.
//
// Strict checks:
//   - all shards completed (manifest.completedAt or schema-equivalent presence)
//   - shared args identical across shards (except seedStart/seeds/phase/out)
//   - no duplicate (cell, seed, mode) triples across shards
//
// Usage:
//   node scripts/balance-phase4-iad-merge.mjs [--shards-root <dir>] [--out <dir>] [--seeds <count|list>]
//
// Defaults:
//   --shards-root results/balance/phase4-iad
//   --out results/balance/phase4-iad/_iad-merged
//   --seeds 8  (looks for _iad-shard-seed_0..7)

import { mkdir, readFile, writeFile } from "node:fs/promises";
import path from "node:path";
import { fileURLToPath } from "node:url";

const repoRoot = path.resolve(path.dirname(fileURLToPath(import.meta.url)), "..");

// Manifest fields that may legitimately differ per shard.
const ALLOWED_SHARD_DIFFS = new Set([
  "seedStart", "seeds", "phase", "out",
  // internal date/timestamp fields the harness may emit:
  "generatedAt",
  // per-shard run-stats fields (not config; legitimately vary per shard):
  "elapsedSeconds", "trialsPerSecond", "trialCount",
]);

function parseArgs(argv) {
  const args = {
    shardsRoot: "results/balance/phase4-iad",
    out: "results/balance/phase4-iad/_iad-merged",
    seeds: [0, 1, 2, 3, 4, 5, 6, 7],
  };
  for (let i = 0; i < argv.length; i += 1) {
    const flag = argv[i];
    const value = argv[i + 1];
    if (!flag.startsWith("--")) continue;
    if (flag === "--shards-root") { args.shardsRoot = value; i += 1; }
    else if (flag === "--out") { args.out = value; i += 1; }
    else if (flag === "--seeds") {
      if (/^\d+$/.test(value)) {
        const n = Number.parseInt(value, 10);
        args.seeds = Array.from({ length: n }, (_, k) => k);
      } else {
        args.seeds = value.split(",").map((s) => Number.parseInt(s.trim(), 10));
      }
      i += 1;
    } else if (flag === "--help" || flag === "-h") {
      process.stderr.write(`usage: node scripts/balance-phase4-iad-merge.mjs [--shards-root <dir>] [--out <dir>] [--seeds <count|list>]\n`);
      process.exit(0);
    } else {
      throw new Error(`Unknown flag: ${flag}`);
    }
  }
  return args;
}

function shardDirFor(shardsRoot, seed) {
  return path.join(shardsRoot, `_iad-shard-seed_${seed}`);
}

async function readJsonIfExists(p) {
  try { return JSON.parse(await readFile(p, "utf8")); }
  catch (e) { if (e.code === "ENOENT") return null; throw e; }
}

async function readTextIfExists(p) {
  try { return await readFile(p, "utf8"); }
  catch (e) { if (e.code === "ENOENT") return null; throw e; }
}

function diffArgs(a, b) {
  const keys = new Set([...Object.keys(a || {}), ...Object.keys(b || {})]);
  const diffs = [];
  for (const k of keys) {
    if (ALLOWED_SHARD_DIFFS.has(k)) continue;
    const av = JSON.stringify(a?.[k]);
    const bv = JSON.stringify(b?.[k]);
    if (av !== bv) diffs.push({ key: k, a: av, b: bv });
  }
  return diffs;
}

function concatCsv(contents) {
  if (contents.length === 0) return "";
  const first = contents[0];
  const firstHeaderEnd = first.indexOf("\n");
  if (firstHeaderEnd < 0) return first;
  const header = first.slice(0, firstHeaderEnd + 1);
  const pieces = [first];
  for (let i = 1; i < contents.length; i += 1) {
    const text = contents[i];
    const headerEnd = text.indexOf("\n");
    const ownHeader = headerEnd < 0 ? text : text.slice(0, headerEnd + 1);
    if (ownHeader !== header) {
      throw new Error(`shard CSV header mismatch:\n  expected: ${header.trim()}\n  shard[${i}]: ${ownHeader.trim()}`);
    }
    const body = headerEnd < 0 ? "" : text.slice(headerEnd + 1);
    if (body.length > 0) pieces.push(body);
  }
  let merged = pieces.join("");
  if (!merged.endsWith("\n")) merged += "\n";
  return merged;
}

async function main() {
  const opts = parseArgs(process.argv.slice(2));
  const outAbs = path.resolve(repoRoot, opts.out);

  console.log(`[balance-iad-merge] shards-root=${opts.shardsRoot} out=${opts.out} seeds=${opts.seeds.join(",")}`);

  const shards = [];
  for (const seed of opts.seeds) {
    const dirAbs = path.resolve(repoRoot, shardDirFor(opts.shardsRoot, seed));
    const manifest = await readJsonIfExists(path.join(dirAbs, "manifest.json"));
    if (!manifest) throw new Error(`shard seed=${seed}: manifest.json missing at ${dirAbs}`);
    const trialOutcomes = await readTextIfExists(path.join(dirAbs, "trial-outcomes.csv"));
    if (!trialOutcomes) throw new Error(`shard seed=${seed}: trial-outcomes.csv missing`);
    const bayesRegret = await readTextIfExists(path.join(dirAbs, "bayes-regret.csv"));
    if (!bayesRegret) throw new Error(`shard seed=${seed}: bayes-regret.csv missing`);
    const signatureObs = await readTextIfExists(path.join(dirAbs, "signature-observations.jsonl"));
    shards.push({ seed, dirAbs, manifest, trialOutcomes, bayesRegret, signatureObs });
  }

  // Strict checks: shard args identical except allowed diffs
  const refArgs = shards[0].manifest;
  for (let i = 1; i < shards.length; i += 1) {
    // The balance manifest stores args at the top level (phase, out, ...) rather than nested.
    // diffArgs handles missing keys gracefully.
    const diffs = diffArgs(refArgs, shards[i].manifest)
      .filter((d) => !["modeDefinitions", "presets", "cases", "trials"].includes(d.key));
    if (diffs.length > 0) {
      const lines = diffs.slice(0, 5).map((d) => `  ${d.key}: shard[0]=${d.a} shard[${i}]=${d.b}`);
      throw new Error(`shard manifest mismatch (shard[0] vs shard[${i}], seed=${shards[i].seed}):\n${lines.join("\n")}`);
    }
  }
  // seed-set uniqueness
  const seedSet = new Set();
  for (const s of shards) {
    if (seedSet.has(s.seed)) throw new Error(`duplicate seed=${s.seed} across shards`);
    seedSet.add(s.seed);
  }
  console.log(`[balance-iad-merge] strict checks passed: ${shards.length} shards, manifests consistent`);

  // Merge CSVs and JSONL
  const mergedTrialOutcomes = concatCsv(shards.map((s) => s.trialOutcomes));
  const mergedBayesRegret = concatCsv(shards.map((s) => s.bayesRegret));
  const mergedSignatureObs = shards.every((s) => s.signatureObs != null)
    ? shards.map((s) => s.signatureObs.endsWith("\n") ? s.signatureObs : s.signatureObs + "\n").join("")
    : null;

  // Build merged manifest. Balance manifest is mostly at top level; pick keys
  // that make sense merged.
  const mergedManifest = {
    schema: "sundog.balance.phase4-iad.merged.v1",
    purpose: "Merged Balance IAD shards — output mirrors a single 8-seed invocation for the IAD-style regret reducer.",
    mergedFrom: shards.map((s) => ({
      seed: s.seed,
      shardDir: path.relative(repoRoot, s.dirAbs),
      phase: s.manifest.phase,
      modes: s.manifest.modes,
    })),
    phase: "phase4-balance-iad-merged",
    out: path.relative(repoRoot, outAbs).replaceAll("/", path.sep),
    modes: refArgs.modes,
    modeDefinitions: refArgs.modeDefinitions,
    seedStart: Math.min(...shards.map((s) => s.seed)),
    seeds: shards.length,
    presets: refArgs.presets,
    shardCount: shards.length,
  };

  await mkdir(outAbs, { recursive: true });
  await writeFile(path.join(outAbs, "manifest.json"), `${JSON.stringify(mergedManifest, null, 2)}\n`, "utf8");
  await writeFile(path.join(outAbs, "trial-outcomes.csv"), mergedTrialOutcomes, "utf8");
  await writeFile(path.join(outAbs, "bayes-regret.csv"), mergedBayesRegret, "utf8");
  if (mergedSignatureObs != null) await writeFile(path.join(outAbs, "signature-observations.jsonl"), mergedSignatureObs, "utf8");

  console.log(`[balance-iad-merge] wrote merged output to ${opts.out}`);
  console.log(`[balance-iad-merge]   manifest.json (${shards.length} shards)`);
  console.log(`[balance-iad-merge]   trial-outcomes.csv (${mergedTrialOutcomes.split("\n").length - 2} data rows)`);
  console.log(`[balance-iad-merge]   bayes-regret.csv (${mergedBayesRegret.split("\n").length - 2} data rows)`);
  if (mergedSignatureObs != null) console.log(`[balance-iad-merge]   signature-observations.jsonl (${mergedSignatureObs.split("\n").filter(Boolean).length} lines)`);
  console.log("");
  console.log("─── next step ─────────────────────────────────────────────────");
  console.log(`node scripts/balance-phase4-iad-regret.mjs --in ${opts.out}`);
}

main().catch((err) => {
  console.error(`[balance-iad-merge] fatal: ${err.stack || err.message}`);
  process.exit(2);
});
